# This file is auto-populated by ``git archive --export-subst`` (see top-level
# .gitattributes).  When git creates a release tarball/zip it substitutes the
# $Format:…$ placeholder with the actual commit hash.  In a live git working
# tree the placeholder string "$Format:…$" is left unexpanded, which signals
# the runtime fallback in _get_git_version() to call ``git describe`` instead.
#
# Do NOT edit this file manually.  It is generated at archive time.

_GIT_ARCHIVE_HASH = "$Format:%H$"
_GIT_ARCHIVE_REF  = "$Format:%D$"    # decorated refs: "tag: v0.3, HEAD -> main"
